<template>
    <div id="show-blogs">
        <h1>All Blog Articles</h1>
        <div v-for="blog in blogs" :key="blog.id" class="single-blog">
        <router-link v-bind:to="'/blog/' + blog.id"><h2>{{blog.title}}</h2></router-link>
        <article>{{blog.content}}</article>
        </div>
    </div>
</template>

<script>


export default {
  components:{

  },
  data(){
    return{
        blogs:[]
    }
},
methods: {

  },
  created(){
      this.$http.get('https://alanwebsite-484a3.firebaseio.com/posts.json').then(function(data){
         return data.json();
      }).then(function(data){
          var blogsArray = [];
          for(let key in data){
              data[key].id = key
              blogsArray.push(data[key])
          }
          this.blogs = blogsArray;
      })
  }
}
</script>

